const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body?.body || webhookData.body;

const eventId = body.event_id || body.record?.id;
const projectId = body.project_id || body.record?.project_id;
const payload = body.payload || body.record?.payload || {};

if (!projectId) {
  throw new Error('No project_id found in webhook payload');
}

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    contractor_code: payload.contractor_code || 'UNKNOWN',
    pdf_storage_path: payload.pdf_storage_path
  }
};

// Parse CSV from Vision API - V4 mit Raum-Support
const input = $input.first().json;
const csvText = (input.text || input.content?.[0]?.text || input.response || '').trim();
if (!csvText) {
  throw new Error('Empty Vision API response');
}
const eventData = $('Extract Event Data').first().json;
const lines = csvText.split('\n').filter(line => line.trim());
const positions = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();

  // Skip header or invalid lines
  if (line.toLowerCase().includes('room|') || !line.includes('|')) continue;

  const parts = line.split('|');
  if (parts.length < 6) continue;

  const room = parts[0].trim();
  const position_code = parts[1].trim().replace(/\.$/, '');
  const title = parts[2].trim();
  const quantity = parseFloat(parts[3].trim().replace(',', '.')) || 1;
  const unit = parts[4].trim() || 'psch';
  const price = parts[5] ? parseFloat(parts[5].trim().replace(',', '.')) : null;
  const payer = parts[6] ? parts[6].trim() : 'SAGA';
  const trade = ''; // SAGA PDFs haben keine Gewerk-Überschriften

  if (!title || !room) continue;

  positions.push({
    room,
    position_code,
    title,
    quantity,
    unit,
    price,
    payer,
    trade,
    position_number: positions.length + 1,
    project_id: eventData.project_id,
    contractor_code: eventData.contractor_code,
    event_id: eventData.event_id
  });
}

if (positions.length === 0) {
  throw new Error('No positions extracted from PDF');
}

return positions.map(p => ({ json: p }));

// Build batch insert query - V4 mit Raum/Section Support
const offerId = $('Create/Get Offer').first().json.id;
const parsedPositions = $('Parse CSV').all().map(i => i.json);
const matchResults = $('Match Catalog').all().map(i => i.json);
const sectionsResult = $('Insert Sections').all();

// Build section map: room name → section id
const sectionMap = {};
for (const row of sectionsResult) {
  if (row.json.id && row.json.title) {
    sectionMap[row.json.title] = row.json.id;
  }
}

if (parsedPositions.length === 0) {
  throw new Error('No positions to insert');
}

const matchMap = {};
parsedPositions.forEach((pos, idx) => {
  const match = matchResults[idx];
  if (match && match.catalog_position_v2_id) {
    matchMap[idx] = match;
  }
});

const escapeStr = (s) => (s || '').replace(/'/g, "''");

const values = parsedPositions.map((p, idx) => {
  const match = matchMap[idx];
  const catId = match?.catalog_position_v2_id ? `'${match.catalog_position_v2_id}'::uuid` : 'NULL';
  const price = p.price ?? 'NULL';
  const sectionId = sectionMap[p.room] ? `'${sectionMap[p.room]}'::uuid` : 'NULL';

  return `(
    '${offerId}'::uuid,
    ${catId},
    ${sectionId},
    ${p.position_number || idx + 1},
    '${escapeStr(p.position_code || '')}',
    '${escapeStr(p.title)}',
    '${escapeStr(p.unit)}',
    ${price},
    ${p.quantity}
  )`;
}).join(',\n');

const query = `
INSERT INTO offer_positions (
  offer_id,
  catalog_position_v2_id,
  section_id,
  position_number,
  catalog_code,
  title,
  unit,
  unit_price,
  quantity
) VALUES ${values}
ON CONFLICT DO NOTHING
RETURNING id;
`;

const eventData = $('Extract Event Data').first().json;

return {
  json: {
    query,
    offer_id: offerId,
    project_id: eventData.project_id,
    event_id: eventData.event_id,
    total_positions: parsedPositions.length,
    matched_count: Object.keys(matchMap).length,
    sections_count: Object.keys(sectionMap).length
  }
};

const webhookData = $('Webhook Trigger').first().json;

// Handle nested body.body structure
const body = webhookData.body?.body || webhookData.body;

const eventId = body.event_id || body.record?.id;
const projectId = body.project_id || body.record?.project_id;
const payload = body.payload || body.record?.payload || {};

if (!projectId) {
  throw new Error('No project_id found in webhook payload');
}
if (!eventId) {
  throw new Error('No event_id found in webhook payload');
}

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    contractor_code: payload.contractor_code || 'UNKNOWN',
    pdf_storage_path: payload.pdf_storage_path || null
  }
};

