// Extract unique rooms and create sections
const offerId = $('Create/Get Offer').first().json.id;
const positions = $('Parse CSV').all().map(i => i.json);

// Get unique rooms in order of appearance
const rooms = [];
const seen = new Set();
for (const pos of positions) {
  if (pos.room && !seen.has(pos.room)) {
    seen.add(pos.room);
    rooms.push(pos.room);
  }
}

if (rooms.length === 0) {
  return { json: { offer_id: offerId, sections: {} } };
}

// Build INSERT query for sections
const escapeStr = (s) => (s || '').replace(/'/g, "''");

const values = rooms.map((room, idx) => 
  `('${offerId}'::uuid, ${idx + 1}, '${escapeStr(room)}')`
).join(',\n');

const query = `
INSERT INTO offer_sections (offer_id, section_number, title)
VALUES ${values}
ON CONFLICT (offer_id, title) DO UPDATE SET updated_at = now()
RETURNING id, title;
`;

return { json: { query, offer_id: offerId, rooms } };

